use std::fs; use std::path::Path; use crate::core::buffer::Buffer; pub fn save_to_file(path: &str, buffer: &Buffer) -> std::io::Result<()> { fs::write(path, buffer.get_text()) } pub fn load_from_file(path: &str) -> std::io::Result<Buffer> { let content = fs::read_to_string(path)?; let mut buffer = Buffer::new(); buffer.lines = content.lines().map(|s| s.to_string()).collect(); Ok(buffer) }
